/**
 * Post-processes schema-doc.md (generated by db-schema-toolkit) by injecting
 * column-level comments from SCHEMA_COLUMN_COMMENTS into the Markdown tables.
 *
 * Called by the `db-schema.yaml` workflow between the export and wiki publish
 * steps. Can also be run locally after generating schema-doc.md.
 */
import { existsSync, readFileSync, realpathSync, writeFileSync } from "node:fs";
import { register } from "node:module";
import { resolve } from "node:path";
import { fileURLToPath } from "node:url";

const COMMENT_HEADER = "Commentaire";
const TABLE_HEADER_RE = /^#{2,3}\s+app_(\w+)/;

/** @param {string} line @returns {string[]} */
function parseCells(line) {
	const s = line.trim();
	const inner = s.startsWith("|") ? s.slice(1) : s;
	const withoutTrailing = /(?<!\\)\|$/.test(inner) ? inner.slice(0, -1) : inner;
	return withoutTrailing.split(/(?<!\\)\|/).map((c) => c.trim());
}

/** @param {string[]} cells @returns {string} */
function buildRow(cells) {
	return `| ${cells.join(" | ")} |`;
}

/** @param {string} line @returns {boolean} */
function isSeparatorRow(line) {
	const cells = parseCells(line);
	return cells.length > 0 && cells.every((c) => /^:?-+:?$/.test(c));
}

/**
 * Injects comments from the map into the Markdown table rows.
 *
 * @param {string} content
 * @param {Record<string, Record<string, string>>} comments
 * @returns {{ output: string, injectedByTable: Record<string, number>, warningTables: string[] }}
 */
export function processMarkdown(content, comments) {
	const lines = content.split("\n");

	let currentTable = /** @type {string | null} */ (null);
	let tablePhase = /** @type {"none" | "header" | "separator" | "data"} */ (
		"none"
	);
	let hasCommentColumn = false;
	const injectedByTable = /** @type {Record<string, number>} */ ({});

	const output = lines.map((line) => {
		const tableMatch = line.match(TABLE_HEADER_RE);
		if (tableMatch) {
			currentTable = tableMatch[1] ?? null;
			tablePhase = "none";
			hasCommentColumn = false;
			return line;
		}

		if (!line.trimStart().startsWith("|")) {
			if (tablePhase !== "none") {
				tablePhase = "none";
				hasCommentColumn = false;
			}
			return line;
		}

		if (tablePhase === "none") {
			tablePhase = "header";
			const cells = parseCells(line);
			hasCommentColumn = cells.includes(COMMENT_HEADER);
			return hasCommentColumn ? line : buildRow([...cells, COMMENT_HEADER]);
		}

		if (tablePhase === "header" && isSeparatorRow(line)) {
			tablePhase = "separator";
			if (hasCommentColumn) return line;
			return buildRow([...parseCells(line), "---"]);
		}

		if (tablePhase === "separator") tablePhase = "data";

		const cells = parseCells(line);
		const dataCells = hasCommentColumn ? cells.slice(0, -1) : cells;
		const colName = dataCells[0] ?? "";
		const rawComment = currentTable
			? (comments[currentTable]?.[colName] ?? "")
			: "";
		const comment = rawComment.replace(/\|/g, "\\|");

		if (rawComment && currentTable) {
			injectedByTable[currentTable] = (injectedByTable[currentTable] ?? 0) + 1;
		}

		return buildRow([...dataCells, comment]);
	});

	const warningTables = Object.keys(comments).filter(
		(t) => !new RegExp(`^#{2,3}\\s+app_${t}`, "m").test(content),
	);

	return { output: output.join("\n"), injectedByTable, warningTables };
}

const isMain = (() => {
	const entry = process.argv[1];
	if (!entry) return false;
	try {
		return fileURLToPath(import.meta.url) === realpathSync(entry);
	} catch {
		return false;
	}
})();

if (isMain) {
	register("tsx/esm", import.meta.url);

	const schemaDocPath = resolve(process.cwd(), "schema-doc.md");
	if (!existsSync(schemaDocPath)) {
		console.error(
			`[post-process] Error: schema-doc.md not found at ${schemaDocPath}`,
		);
		process.exit(1);
	}

	const commentsUrl = new URL(
		"../src/server/db/schema-comments.ts",
		import.meta.url,
	).href;
	const { SCHEMA_COLUMN_COMMENTS } = await import(commentsUrl);

	const content = readFileSync(schemaDocPath, "utf8");
	const { output, injectedByTable, warningTables } = processMarkdown(
		content,
		SCHEMA_COLUMN_COMMENTS,
	);

	let total = 0;
	for (const [table, count] of Object.entries(injectedByTable)) {
		console.log(`[post-process] ${table}: ${count} comment(s) injected`);
		total += count;
	}
	if (total === 0) {
		console.log(
			"[post-process] No comments to inject (SCHEMA_COLUMN_COMMENTS is empty)",
		);
	}
	for (const t of warningTables) {
		console.warn(
			`[post-process] WARNING: table "${t}" from SCHEMA_COLUMN_COMMENTS not found in schema-doc.md`,
		);
	}

	writeFileSync(schemaDocPath, output, "utf8");
	console.log(
		`[post-process] Done — ${total} comment(s) injected into schema-doc.md`,
	);
}
